const error = $input.first().json;

const bugReport = {
  timestamp: new Date().toISOString(),
  workflow: error.workflow?.name || 'unknown',
  node: error.execution?.lastNodeExecuted || 'unknown',
  error_message: error.execution?.error?.message || 'No message',
  error_stack: error.execution?.error?.stack || 'No stack',
  execution_id: error.execution?.id
};

return [{json: bugReport}];

