parameters.jsCode:
const codexResponse = $input.first().json;
const fix = codexResponse.choices?.[0]?.message?.content || 'No fix generated';

// 解析代码块
const codeBlocks = fix.match(/```[\w]*\n([\s\S]*?)```/g) || [];
const extractedCode = codeBlocks.map(block => 
  block.replace(/```[\w]*\n/, '').replace(/```$/, '')
).join('\n\n');

return [{
  json: {
    fix_description: fix.slice(0, 500),
    code_changes: extractedCode,
    original_error: $input.first().json
  }
}];

